/* Check for sensor timeout - go to safe state if either sensor is stale */
 bool turbidity_stale = (controller->has_valid_turbidity && 
                         (input.now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);
 bool level_stale = (controller->has_valid_level && 
                     (input.now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS);

 if (turbidity_stale || level_stale || input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
     input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
     controller->has_valid_turbidity = false;
     controller->has_valid_level = false;
     controller->clear_streak_count = 0;
     controller->settling_started_ms = 0U;
     controller_set_safe_idle(controller);
     output.timed_out = true;
 } else if (input.kind == CONTROLLER_INPUT_NONE) {
     /* Idle step - check for timeout, otherwise continue current state */
     /* Do nothing, keep current state and outputs */
 } else {
     /* Valid input received - update sensor data */
     switch (input.kind) {
     case CONTROLLER_INPUT_TURBIDITY:
         controller->has_valid_turbidity = true;
         controller->last_turbidity_ntu = input.turbidity_ntu;
         controller->last_turbidity_ms = input.now_ms;
         break;
     case CONTROLLER_INPUT_LEVEL:
         controller->has_valid_level = true;
         controller->last_level = input.level;
         controller->last_level_ms = input.now_ms;
         break;
     default:
         break;
     }
 }

 /* Check if we have valid data from both sensors */
 bool has_both_sensors = controller->has_valid_turbidity && controller->has_valid_level;

 /* If we don't have both sensors, stay in safe idle */
 if (!has_both_sensors) {
     controller_set_safe_idle(controller);
 } else {
     /* We have valid sensor data - apply control policy based on current state */
     int turbidity = controller->last_turbidity_ntu;
     int level = controller->last_level;

     switch (controller->state) {
     case CONTROLLER_STATE_SAFE_IDLE:
         /* Stay in safe idle until we have valid sensors (already handled above) */
         break;

     case CONTROLLER_STATE_FILTERING:
         /* Check if we should transition to SETTLING */
         if (level >= CONTROLLER_MIN_PROCESS_LEVEL) {
             if (turbidity <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                 controller->clear_streak_count++;
                 if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                     /* Transition to SETTLING */
                     controller->filter_on = false;
                     controller->drain_open = false;
                     controller->state = CONTROLLER_STATE_SETTLING;
                     controller->settling_started_ms = input.now_ms;
                 }
             } else {
                 /* Turbidity too high - reset clear streak */
                 controller->clear_streak_count = 0;
             }
         } else if (level < CONTROLLER_MIN_PROCESS_LEVEL) {
             /* Level too low - go to COMPLETE */
             controller->filter_on = false;
             controller->drain_open = false;
             controller->state = CONTROLLER_STATE_COMPLETE;
         }
         break;

     case CONTROLLER_STATE_SETTLING:
         /* Check for disturbance - return to FILTERING if turbidity > 40 */
         if (turbidity > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
             controller->clear_streak_count = 0;
             controller->filter_on = true;
             controller->drain_open = false;
             controller->state = CONTROLLER_STATE_FILTERING;
